#include <iostream>
#include <string>
#include <sstream>

class Counter {
private:
    int count;

public:
    Counter(int initial = 0) : count(initial) {}

    Counter& operator++() {
        ++count;
        return *this;
    }

    Counter operator--(int) {
        Counter temp = *this;
        --count;
        return temp;
    }

    int getCount() const {
        return count;
    }
};

int main() {
    std::stringstream ss;

    Counter c1(10);
    ss << "Initial c1: " << c1.getCount() << std::endl;

    Counter& c1_ref = ++c1;
    ss << "After ++c1: " << c1.getCount() << std::endl;
    ss << "c1_ref count: " << c1_ref.getCount() << std::endl;

    Counter c1_old_value = c1--;
    ss << "After c1-- (returned value): " << c1_old_value.getCount() << std::endl;
    ss << "After c1-- (original c1): " << c1.getCount() << std::endl;

    Counter c2(0);
    ss << "Initial c2: " << c2.getCount() << std::endl;

    ++(++c2);
    ss << "After ++(++c2): " << c2.getCount() << std::endl;

    Counter c3(5);
    ss << "Initial c3: " << c3.getCount() << std::endl;
    int result = (c3--).getCount() + (++c3).getCount();
    ss << "Result of (c3--).getCount() + (++c3).getCount(): " << result << std::endl;
    ss << "Final c3: " << c3.getCount() << std::endl;

    std::cout << ss.str();

    return 0;
}
